import socket
import json

class GameServer:
    def __init__(self, host='0.0.0.0', port=8080):
        self.host = host
        self.port = port
        self.players = []
        self.game_state = {}

    def handle(self, client_socket):
        while True:
            data = client_socket.recvfrom(1024)[0]
            if not data:
                break
            request = json.loads(data)
            if request['type'] == 'status':
                self.handle_status(client_socket, request)

    def handle_status(self, client_socket, request):
        response = {
            'players': self.players,
            'game_state': self.game_state
        }
        client_socket.sendto(json.dumps(response).encode(), (request['host'], request['port']))